#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        if (N % 2 == 1 || M % 2 == 1) {
            printf("%d\n", (N - 1) * (M - 1));
        } else {
            printf("%d\n", (N - 2) * (M - 2));
        }
    }
    return 0;
}

