import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            if (N % 2 == 1 || M % 2 == 1) {
                System.out.println((N - 1) * (M - 1));
            } else {
                System.out.println((N - 2) * (M - 2));
            }
        }
    }
}

